class RandomizedSet:
    def __init__(self): self.data, self.pos = [], {}
    def insert(self, val):
        if val in self.pos: return False
        self.pos[val] = len(self.data); self.data.append(val); return True
    def remove(self, val):
        if val not in self.pos: return False
        idx, last = self.pos[val], self.data[-1]
        self.data[idx], self.pos[last] = last, idx
        self.data.pop(); del self.pos[val]; return True
    def getRandom(self): return random.choice(self.data)

